[CmdletBinding()]
param([string]$SelectorPath=(Join-Path $PSScriptRoot 'select-capability-profile.ps1'),[switch]$Json)
$cases=@(@{name='t0';task='Explain dependency injection'},@{name='ui';task='Build accessible UI';tags=@('ui')},@{name='assured';task='Payment migration';tier='T4';risk='Payment';code=$true});$items=@();foreach($case in $cases){$start=[Diagnostics.Stopwatch]::StartNew();$args=@{Task=$case.task;Json=$true};if($case.tags){$args.TaskTag=$case.tags};if($case.tier){$args.RouteTier=$case.tier};if($case.risk){$args.RiskFloor=$case.risk};if($case.code){$args.CodeChange=$true};$r=(& $SelectorPath @args|Out-String)|ConvertFrom-Json;$start.Stop();$items+=[pscustomobject]@{case=$case.name;profile=$r.profile;skillCount=@($r.skills).Count;mcpCount=@($r.mcps).Count;workflowCount=@($r.workflows).Count;durationMs=$start.ElapsedMilliseconds}};$result=[ordered]@{schemaVersion=1;items=$items;interpretation='Counts measure selected capabilities, not loaded framework files.'};if($Json){$result|ConvertTo-Json -Depth 4}else{$items|Format-Table -AutoSize}
